#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5;
struct node{long long w,num;}a[N];
long long n,m,k,cnt,seg[N*2],mst[N*2],now,ans;
bool cmp(node d1,node d2){return d1.w<d2.w;}
int Have(long long p){
    int l=1,r=n,id=1;
    while(l<=r){
        int mid=(l+r)/2;
        if(a[mid].w>=p)id=mid,r=mid-1;
        else l=mid+1;
    }
    return id;
}
int Find(long long p){
    int l=1,r=cnt,id=1;
    while(l<=r){
        int mid=(l+r)/2;
        if(seg[mid]>=p)id=mid,r=mid-1;
        else l=mid+1;
    }
    return id;
}
int main(){
    cin>>n>>m>>k;
    for(int i=1;i<=n;i++){
        cin>>a[i].w>>a[i].num;
        seg[++cnt]=a[i].w,seg[++cnt]=a[i].w-k;
    }
    sort(a+1,a+n+1,cmp);
    sort(seg+1,seg+cnt+1);
    cnt=unique(seg+1,seg+cnt+1)-seg-1;
    now=m;
    for(int i=cnt;i>=1;i--){
        now+=mst[i];
        int id=Have(seg[i]);
        if(a[id].w==seg[i]){
            long long use=min(now,a[id].num);
            ans+=use,now-=use,mst[Find(seg[i]-k)]=use;
        }
    }
    cout<<ans;
    return 0;
}
